import{a8 as s,L as a,Z as n,aK as t}from"./chunks/framework.BnqUBHC7.js";const u=JSON.parse('{"title":"Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1782477269000}'),o={name:"guide/index.md"};function i(r,e,l,d,c,p){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="guide" tabindex="-1">Guide <a class="header-anchor" href="#guide" aria-label="Permalink to &quot;Guide&quot;">​</a></h1><p>The guide section covers the concepts behind vuecs in depth. Read these once, and the rest of the docs will read more like a reference.</p><h2 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h2><p>How vuecs is configured in an app — read these in order:</p><ul><li><strong><a href="/guide/undesigned-components">Undesigned Components</a></strong> — the core idea: components ship structure, behavior, and a11y; themes supply the design. Who that split is for, and what it enables for library authors.</li><li><strong><a href="/guide/theme-system">Theme System</a></strong> — the four-layer class resolution chain (defaults → themes → overrides → instance props).</li><li><strong><a href="/guide/variants">Variants</a></strong> — structured variants, compound variants, and the merge rules across layers.</li><li><strong><a href="/guide/behavioral-defaults">Behavioral Defaults</a></strong> — the parallel resolution system for non-class props (button text, placeholders, content strings) — the i18n hook.</li><li><strong><a href="/guide/design-tokens">Design Tokens</a></strong> — <code>@vuecs/design</code>, the CSS custom-property layer underneath the class system.</li><li><strong><a href="/guide/composables">Composables</a></strong> — the full composable surface: wrapper-building primitives from <code>@vuecs/core</code>, color mode + palette from <code>@vuecs/design</code>, the locale source from <code>@vuecs/locale</code>.</li></ul><h2 id="authoring" tabindex="-1">Authoring <a class="header-anchor" href="#authoring" aria-label="Permalink to &quot;Authoring&quot;">​</a></h2><p>For library authors building components or themes on the same machinery:</p><ul><li><strong><a href="/guide/build-themable-component">Build Your Own Themable Component</a></strong> — worked example: register a third-party component on the theme system so consumers reskin it through the same <code>app.use(vuecs, …)</code> call.</li><li><strong><a href="/guide/primitive">Primitive (as / asChild)</a></strong> — <code>&lt;VCPrimitive&gt;</code>, the generic render-target building block behind <code>as</code> / <code>asChild</code>.</li><li><strong><a href="/guide/composing-themes">Composing Themes</a></strong> — <code>defineTheme()</code> for authoring themes that build on existing ones.</li><li><strong><a href="/guide/bridging-css-frameworks">Bridging CSS Frameworks</a></strong> — wire a non-Tailwind framework&#39;s runtime tokens onto the design system so palette switching reaches its native components.</li></ul><h2 id="deep-dives" tabindex="-1">Deep dives <a class="header-anchor" href="#deep-dives" aria-label="Permalink to &quot;Deep dives&quot;">​</a></h2><ul><li><strong><a href="/guide/navigation">Navigation</a></strong> — <code>@vuecs/navigation</code>&#39;s per-call-site <code>:data</code> items, the shared reactive registry for dependent navs, and soft <code>vue-router</code> integration.</li><li><strong><a href="/guide/validation-feedback">Validation Feedback</a></strong> — <code>&lt;VCFormGroup :validation&gt;</code>, the <code>FieldValidation</code> contract, and how severity flows down to child inputs.</li></ul><h2 id="mental-model" tabindex="-1">Mental model <a class="header-anchor" href="#mental-model" aria-label="Permalink to &quot;Mental model&quot;">​</a></h2><p>vuecs has three orthogonal systems that you configure independently in <code>app.use(vuecs, ...)</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─ themes/overrides ─────────────────────┐  → CSS class strings</span></span>
<span class="line"><span>│  layered resolution → class name(s)     │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span>┌─ defaults ─────────────────────────────┐  → behavioral values (text, booleans)</span></span>
<span class="line"><span>│  layered resolution → unwrapped value   │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span>┌─ design tokens (CSS variables) ────────┐  → concrete colors / radii</span></span>
<span class="line"><span>│  flip under .dark, swap via setColorPalette  │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼  components reference the first two via composables,</span></span>
<span class="line"><span>           the third via the class strings the first system produces</span></span></code></pre></div><p>Each system has its own composable: <code>useComponentTheme</code>, <code>useComponentDefaults</code>. The design-token layer needs no composable — it&#39;s pure CSS.</p>`,14)])])}const g=s(o,[["render",i]]);export{u as __pageData,g as default};
